// generate-og.mjs
// Build-time OG image pre-generation for docs pages.
//
// Runs in Node.js BEFORE vite build (sync-docs → generate-og → vite build),
// so @takumi-rs/core native Napi-rs bindings are available — no WASM fallback,
// no ssr.external constraints.
//
// For every page enumerated from content/docs (the Fumadocs content directory
// generated by sync-docs.mjs), this script:
//   1. Parses frontmatter to get title + description.
//   2. Derives URL slugs using the same logic as source.ts markdownPathToSlugs.
//   3. Renders a 1200×630 WebP with the fumadocs-ui/og/takumi template.
//   4. Writes the file to public/og/docs/{...slugs}/image.webp — which is the
//      exact URL returned by getPageImage() in source.ts.
//
// The static files land in dist/ via Vite's public directory copy, so the
// Cloudflare Worker serves them directly without hitting any route handler.
// The og/docs/$.tsx route is kept as a fallback to /og/og.png for any slug
// that doesn't have a pre-generated image.

import { existsSync } from 'node:fs'
import { mkdir, readdir, readFile, writeFile } from 'node:fs/promises'
import { dirname, join, relative, sep } from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const CONTENT_DIR = join(__dirname, '../content/docs')
const PUBLIC_OG_DIR = join(__dirname, '../public/og/docs')

// ---------------------------------------------------------------------------
// Frontmatter parser — same simplified approach as sync-docs.mjs
// ---------------------------------------------------------------------------
function parseFrontmatter(src) {
  const m = src.match(/^---\n([\s\S]*?)\n---\n?/)
  if (!m) return {}
  const data = {}
  for (const line of m[1].split('\n')) {
    const kv = line.match(/^(\w[\w-]*):\s*(.*)$/)
    if (!kv) continue
    let value = kv[2].trim()
    if (
      (value.startsWith('"') && value.endsWith('"')) ||
      (value.startsWith("'") && value.endsWith("'"))
    ) {
      value = value.slice(1, -1)
    }
    data[kv[1]] = value
  }
  return data
}

// ---------------------------------------------------------------------------
// Slug derivation — mirrors source.ts markdownPathToSlugs + Fumadocs loader
//
// content/docs/getting-started.md          → ['getting-started']
// content/docs/getting-started/index.md   → ['getting-started']
// content/docs/advanced/config.md          → ['advanced', 'config']
// content/docs/index.md                    → []  (root page)
// ---------------------------------------------------------------------------
function pathToSlugs(relPath) {
  // relPath: e.g. "getting-started.md", "advanced/config.md", "index.md"
  const withoutExt = relPath.replace(/\.md$/, '')
  const segments = withoutExt.split('/')
  if (segments[segments.length - 1] === 'index') {
    segments.pop()
  }
  return segments.filter(Boolean)
}

// ---------------------------------------------------------------------------
// Recursive markdown file walk (skip meta.json — it uses .json extension anyway)
// ---------------------------------------------------------------------------
async function walk(dir) {
  const entries = await readdir(dir, { withFileTypes: true })
  const files = []
  for (const entry of entries) {
    const full = join(dir, entry.name)
    if (entry.isDirectory()) {
      files.push(...(await walk(full)))
    } else if (entry.name.endsWith('.md')) {
      files.push(full)
    }
  }
  return files
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------
async function main() {
  if (!existsSync(CONTENT_DIR)) {
    console.error(
      '[generate-og] content/docs not found — run sync-docs.mjs first.',
    )
    process.exit(1)
  }

  // Import lazily so the native @takumi-rs/core binding resolves properly.
  // These are ES module packages; dynamic import works fine in .mjs.
  const [{ render }, { generate }] = await Promise.all([
    import('takumi-js'),
    import('fumadocs-ui/og/takumi'),
  ])

  const files = await walk(CONTENT_DIR)
  let count = 0
  const errors = []

  for (const absPath of files) {
    const rel = relative(CONTENT_DIR, absPath).split(sep).join('/')
    const content = await readFile(absPath, 'utf8')
    const fm = parseFrontmatter(content)

    const slugs = pathToSlugs(rel)
    const title = fm.title || slugs[slugs.length - 1] || 'chmonitor docs'
    const description = fm.description || undefined

    // Mirrors getPageImage(): /og/docs/{...slugs}/image.webp
    const outPath = join(PUBLIC_OG_DIR, ...slugs, 'image.webp')
    await mkdir(dirname(outPath), { recursive: true })

    try {
      const bytes = await render(
        generate({
          title,
          description,
          site: 'chmonitor',
          // ClickHouse yellow as primary accent
          primaryColor: 'rgba(255,204,0,0.35)',
          primaryTextColor: 'rgb(255,204,0)',
        }),
        { width: 1200, height: 630, format: 'webp' },
      )

      await writeFile(outPath, bytes)
      count++
    } catch (err) {
      errors.push({ rel, err })
      console.warn(`[generate-og] WARN: failed to render ${rel}: ${err.message}`)
    }
  }

  console.log(`[generate-og] ${count} OG image(s) → public/og/docs/`)
  if (errors.length > 0) {
    console.warn(`[generate-og] ${errors.length} page(s) failed to render.`)
  }
}

await main()
